// $input.all() = all customer orders from WooCommerce node
// Why returnAll: partial history skews frequency + monetary scores
const orders = $input.all();

// Trigger data: email, name, customer_id from original webhook payload
// Skip karne se customer ka identity nahi milega Klaviyo/Slack ke liye
const trigger = $('WooCommerce Trigger').first().json;
const customerEmail = trigger.billing?.email || '';
const customerId = trigger.customer_id || 0;
const customerName = ((trigger.billing?.first_name || '') + ' ' + (trigger.billing?.last_name || '')).trim();

const now = new Date();

// Sirf completed orders count karo — cancelled/refunded include karna RFM ko galat karega
const completedOrders = orders.filter(o => o.json.status === 'completed');
const totalOrders = completedOrders.length;

// MONETARY: lifetime value = sum of all completed order totals
const totalSpend = completedOrders.reduce((sum, o) => {
  return sum + parseFloat(o.json.total || '0');
}, 0);

// RECENCY: days since most recent completed order
// fallback 365: agar koi order nahi to recency score 1 (worst) milega
const orderDates = completedOrders
  .map(o => new Date(o.json.date_created))
  .filter(d => !isNaN(d.getTime()));

let daysSinceLastOrder = 365;
if (orderDates.length > 0) {
  const mostRecent = new Date(Math.max(...orderDates.map(d => d.getTime())));
  daysSinceLastOrder = Math.floor((now.getTime() - mostRecent.getTime()) / (1000 * 60 * 60 * 24));
}

// --- RECENCY SCORE (1-5) ---
// Thresholds adjust karo apne store ke purchase cycle ke hisaab se
// e.g. subscription store mein 7/30/60 zyada suitable hai
let recencyScore;
if (daysSinceLastOrder <= 30) recencyScore = 5;
else if (daysSinceLastOrder <= 60) recencyScore = 4;
else if (daysSinceLastOrder <= 90) recencyScore = 3;
else if (daysSinceLastOrder <= 180) recencyScore = 2;
else recencyScore = 1;

// --- FREQUENCY SCORE (1-5) ---
// Thresholds adjust karo average order frequency ke hisaab se
let frequencyScore;
if (totalOrders >= 10) frequencyScore = 5;
else if (totalOrders >= 7) frequencyScore = 4;
else if (totalOrders >= 4) frequencyScore = 3;
else if (totalOrders >= 2) frequencyScore = 2;
else frequencyScore = 1;

// --- MONETARY SCORE (1-5) ---
// Thresholds adjust karo apne store ke AOV (Average Order Value) ke hisaab se
let monetaryScore;
if (totalSpend >= 1000) monetaryScore = 5;
else if (totalSpend >= 500) monetaryScore = 4;
else if (totalSpend >= 200) monetaryScore = 3;
else if (totalSpend >= 100) monetaryScore = 2;
else monetaryScore = 1;

// Total RFM Score — max 15, VIP threshold = 12 (IF node mein set hai)
const rfmScore = recencyScore + frequencyScore + monetaryScore;

return [{
  json: {
    rfm_score: rfmScore,
    recency_score: recencyScore,
    frequency_score: frequencyScore,
    monetary_score: monetaryScore,
    total_orders: totalOrders,
    total_spend: totalSpend,
    days_since_last_order: daysSinceLastOrder,
    customer_email: customerEmail,
    customer_id: customerId,
    customer_name: customerName
  }
}];

